## STEP 1: File System Access Script

Create this file at `C:\TAD\file-handler.js`:

```javascript
const fs = require('fs');
const path = require('path');

const COMMANDS = {
  read: (filePath) => {
    try {
      return fs.readFileSync(path.join('C:\\TAD', filePath), 'utf8');
    } catch (e) {
      return `ERROR: ${e.message}`;
    }
  },

  write: (filePath, content) => {
    try {
      fs.writeFileSync(path.join('C:\\TAD', filePath), content, 'utf8');
      return `SUCCESS: Written to ${filePath}`;
    } catch (e) {
      return `ERROR: ${e.message}`;
    }
  },

  append: (filePath, content) => {
    try {
      fs.appendFileSync(path.join('C:\\TAD', filePath), content, 'utf8');
      return `SUCCESS: Appended to ${filePath}`;
    } catch (e) {
      return `ERROR: ${e.message}`;
    }
  },

  list: (dirPath = '') => {
    try {
      return fs.readdirSync(path.join('C:\\TAD', dirPath));
    } catch (e) {
      return `ERROR: ${e.message}`;
    }
  }
};

console.log(COMMANDS[process.argv[2]]?.(process.argv[3], process.argv[4]) || 'Command not found');
```

**Usage:**
```
node C:\TAD\file-handler.js read research_log.md
node C:\TAD\file-handler.js write research_log.md "content here"
node C:\TAD\file-handler.js append research_log.md "new line"
node C:\TAD\file-handler.js list
```

