## STEP 3: Web Scraping + HTTP Tool

Create this file at `C:\TAD\research-tool.js`:

```javascript
const https = require('https');
const http = require('http');

function fetch(url) {
  return new Promise((resolve, reject) => {
    const protocol = url.startsWith('https') ? https : http;
    protocol.get(url, (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => resolve(data));
    }).on('error', reject);
  });
}

async function searchAndParse(query) {
  try {
    // Simple approach: fetch from a public API or documentation
    const url = `https://api.duckduckgo.com/?q=${encodeURIComponent(query)}&format=json`;
    const result = await fetch(url);
    console.log(result);
  } catch (e) {
    console.error(`ERROR: ${e.message}`);
  }
}

searchAndParse(process.argv[2]);
```

**Usage:**
```
node C:\TAD\research-tool.js "multi-agent coordination frameworks"
```

